{action_set_definitions}: {
  "get_sector_telemetry": {
    "description": "Retrieves the current network state for a specific sector, including link utilization, traffic matrix, and global performance metrics like packet loss rate.",
    "parameters": {
      "type": "object",
      "properties": {
        "sector_id": {
          "type": "string",
          "description": "The sector identifier (e.g., 'North-Metro')."
        }
      },
      "required": [
        "sector_id"
      ]
    },
    "example_output": {
      "links": [
        {
          "link_id": "L123",
          "source": "Agg-1",
          "target": "Core-A",
          "capacity_gbps": 100,
          "utilization_pct": 82.5
        }
      ],
      "metrics": {
        "packet_loss_rate": 5e-05,
        "avg_latency": 15
      }
    }
  },
  "get_link_hardware_limits": {
    "description": "Queries the physical hardware constraints of specific links to determine the maximum possible bandwidth capacity.",
    "parameters": {
      "type": "object",
      "properties": {
        "link_ids": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "List of link IDs to check."
        }
      },
      "required": [
        "link_ids"
      ]
    },
    "example_output": {
      "L123": {
        "max_capacity_gbps": 200,
        "is_at_physical_max": false
      }
    }
  },
  "query_topology_for_alternatives": {
    "description": "Scans the network topology to find alternative paths between two nodes that have available headroom. Used to verify path existence before rerouting.",
    "parameters": {
      "type": "object",
      "properties": {
        "source_node": {
          "type": "string"
        },
        "target_node": {
          "type": "string"
        },
        "required_headroom_gbps": {
          "type": "number"
        }
      },
      "required": [
        "source_node",
        "target_node",
        "required_headroom_gbps"
      ]
    },
    "example_output": {
      "available_paths": [
        [
          "Agg-1",
          "Agg-2",
          "Core-A"
        ]
      ],
      "path_headroom_gbps": [
        45.0
      ]
    }
  },
  "apply_capacity_upgrade": {
    "description": "Increases the logical or provisioned bandwidth of a link up to its physical hardware limit.",
    "parameters": {
      "type": "object",
      "properties": {
        "link_id": {
          "type": "string"
        },
        "target_capacity_gbps": {
          "type": "number"
        }
      },
      "required": [
        "link_id",
        "target_capacity_gbps"
      ]
    },
    "example_output": {
      "status": "success",
      "new_capacity_gbps": 150
    }
  },
  "execute_traffic_reroute": {
    "description": "Reconfigures routing tables to move a specific traffic volume to a verified alternative path.",
    "parameters": {
      "type": "object",
      "properties": {
        "source_node": {
          "type": "string"
        },
        "target_node": {
          "type": "string"
        },
        "volume_gbps": {
          "type": "number"
        },
        "path_nodes": {
          "type": "array",
          "items": {
            "type": "string"
          }
        }
      },
      "required": [
        "source_node",
        "target_node",
        "volume_gbps",
        "path_nodes"
      ]
    },
    "example_output": {
      "status": "rerouted",
      "flow_id": "FL-902"
    }
  }
}
